function FlashcardsWidget() {
  const cards = [
    { q: 'What is the capital of France?', a: 'Paris' },
    { q: 'What does HTTP stand for?', a: 'HyperText Transfer Protocol' },
    { q: 'What is 2^10?', a: '1024' }
  ];
  const [index, setIndex] = React.useState(0);
  const [flipped, setFlipped] = React.useState(false);

  function nextCard() {
    setFlipped(false);
    setIndex((index + 1) % cards.length);
  }

  function prevCard() {
    setFlipped(false);
    setIndex((index - 1 + cards.length) % cards.length);
  }

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#0f172a', color: '#e2e8f0', borderRadius: 12, height: '100%', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
      <h3 style={{ margin: 0, marginBottom: 12 }}>Flashcards</h3>
      <div
        onClick={() => setFlipped(!flipped)}
        style={{
          width: '100%',
          flex: 1,
          background: '#1e293b',
          borderRadius: 12,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          textAlign: 'center',
          padding: 20,
          cursor: 'pointer',
          transition: 'transform 0.3s ease',
          transform: flipped ? 'scale(1.02)' : 'scale(1)',
          userSelect: 'none'
        }}
      >
        <div style={{ fontSize: 18, fontWeight: 600 }}>
          {flipped ? cards[index].a : cards[index].q}
        </div>
      </div>
      <div style={{ marginTop: 12, fontSize: 12, color: '#94a3b8' }}>
        Card {index + 1} of {cards.length} — tap card to flip
      </div>
      <div style={{ display: 'flex', gap: 10, marginTop: 12 }}>
        <button onClick={prevCard} style={{ padding: '8px 16px', borderRadius: 6, border: 'none', background: '#334155', color: '#fff', cursor: 'pointer', fontFamily: 'system-ui, sans-serif' }}>Prev</button>
        <button onClick={nextCard} style={{ padding: '8px 16px', borderRadius: 6, border: 'none', background: '#3b82f6', color: '#fff', cursor: 'pointer', fontFamily: 'system-ui, sans-serif' }}>Next</button>
      </div>
    </div>
  );
}
render(<FlashcardsWidget/>);
